## 1. GraphQL Schema

```graphql
# =====================================================
# Scalar 타입 정의
# =====================================================
scalar Upload

# =====================================================
# Enum 타입 정의
# =====================================================

"""사용자 성별"""
enum Gender {
    MALE
    FEMALE
    NON_BINARY
    PREFER_NOT_TO_SAY
}

"""프로필 공개 범위"""
enum ProfileVisibility {
    PUBLIC        # 모든 사용자에게 공개
    FRIENDS_ONLY  # 연결된 사용자에게만 공개
    PRIVATE       # 비공개
}

"""위치 공개 범위"""
enum LocationVisibility {
    EXACT       # 정확한 위치 (km 단위)
    APPROXIMATE # 대략적인 위치 (시/도 단위)
    HIDDEN      # 위치 비공개
}

"""음성 소개 상태"""
enum VoiceIntroStatus {
    ACTIVE    # 활성화됨
    INACTIVE  # 비활성화됨 (업로드 되어 있으나 미사용)
    NONE      # 없음
}

# =====================================================
# 공통 하위 타입
# =====================================================

"""프로필 사진"""
type ProfilePhoto {
    id: ID!
    url: String!
    thumbnailUrl: String!
    order: Int!          # 사진 정렬 순서 (0-based)
    isMain: Boolean!     # 대표 사진 여부
}

"""음성 소개 클립"""
type VoiceIntro {
    id: ID!
    url: String!
    durationSeconds: Int!  # 재생 시간 (초), 최대 60초
    status: VoiceIntroStatus!
    createdAt: String!
}

"""위치 정보"""
type ProfileLocation {
    city: String            # 시/군/구 (공개 범위에 따라 null 가능)
    region: String          # 시/도
    country: String!
    latitude: Float         # EXACT 공개 범위일 때만 반환
    longitude: Float        # EXACT 공개 범위일 때만 반환
    visibility: LocationVisibility!
}

"""공개 범위 설정"""
type PrivacySettings {
    profileVisibility: ProfileVisibility!
    locationVisibility: LocationVisibility!
    showAge: Boolean!        # 나이 표시 여부
    showLastSeen: Boolean!   # 마지막 접속 시간 표시 여부
}

"""사용자 프로필"""
type UserProfile {
    id: ID!
    nickname: String!
    bio: String              # 자기소개 (nullable, 최대 300자)
    birthDate: String        # "YYYY-MM-DD" 형식, 공개 설정에 따라 null
    age: Int                 # 계산된 나이, showAge=false이면 null
    gender: Gender
    photos: [ProfilePhoto!]!
    voiceIntro: VoiceIntro
    interests: [String!]!    # 관심사/태그 목록
    location: ProfileLocation
    privacySettings: PrivacySettings!
    updatedAt: String!
}

# =====================================================
# Input 타입 정의
# =====================================================

"""기본 정보 수정 입력"""
input UpdateProfileBasicInput {
    nickname: String         # 2~20자, 특수문자 제한
    bio: String              # 최대 300자, null이면 기존 유지, "" 이면 삭제
    birthDate: String        # "YYYY-MM-DD", 만 18세 이상
    gender: Gender
}

"""위치 정보 수정 입력"""
input UpdateProfileLocationInput {
    latitude: Float!
    longitude: Float!
    # city, region, country는 서버에서 좌표 기반 역지오코딩으로 자동 결정
}

"""공개 범위 설정 수정 입력"""
input UpdatePrivacySettingsInput {
    profileVisibility: ProfileVisibility
    locationVisibility: LocationVisibility
    showAge: Boolean
    showLastSeen: Boolean
}

"""프로필 사진 순서 변경 입력"""
input ReorderProfilePhotosInput {
    photoIds: [ID!]!  # 새 순서대로 정렬된 photo ID 목록 (최대 6장)
}

"""음성 소개 상태 변경 입력"""
input UpdateVoiceIntroStatusInput {
    status: VoiceIntroStatus!  # ACTIVE 또는 INACTIVE만 허용 (NONE은 deleteVoiceIntro 사용)
}

"""관심사 수정 입력"""
input UpdateProfileInterestsInput {
    interests: [String!]!  # 최대 10개, 각 태그 최대 20자
}

# =====================================================
# Payload (Response) 타입
# =====================================================

"""프로필 수정 결과"""
type UpdateProfilePayload {
    profile: UserProfile!
}

"""프로필 사진 업로드 결과"""
type UploadProfilePhotoPayload {
    photo: ProfilePhoto!
    profile: UserProfile!  # 업데이트된 전체 프로필
}

"""음성 소개 업로드 결과"""
type UploadVoiceIntroPayload {
    voiceIntro: VoiceIntro!
}

# =====================================================
# Query
# =====================================================

extend type Query {
    """내 프로필 조회"""
    myProfile: UserProfile!

    """다른 사용자 프로필 조회 (공개 범위 적용됨)"""
    userProfile(userId: ID!): UserProfile
}

# =====================================================
# Mutation
# =====================================================

extend type Mutation {
    # --- 기본 정보 ---

    """프로필 기본 정보 수정 (닉네임, 자기소개, 생년월일, 성별)"""
    updateProfileBasic(input: UpdateProfileBasicInput!): UpdateProfilePayload!

    """관심사/태그 수정 (전체 교체)"""
    updateProfileInterests(input: UpdateProfileInterestsInput!): UpdateProfilePayload!

    # --- 미디어 ---

    """프로필 사진 업로드 (최대 6장)"""
    uploadProfilePhoto(file: Upload!): UploadProfilePhotoPayload!

    """프로필 사진 삭제"""
    deleteProfilePhoto(photoId: ID!): UpdateProfilePayload!

    """프로필 사진 순서/대표 사진 변경"""
    reorderProfilePhotos(input: ReorderProfilePhotosInput!): UpdateProfilePayload!

    """음성 소개 업로드 (최대 60초, MP3/M4A/AAC)"""
    uploadVoiceIntro(file: Upload!): UploadVoiceIntroPayload!

    """음성 소개 활성화/비활성화"""
    updateVoiceIntroStatus(input: UpdateVoiceIntroStatusInput!): UploadVoiceIntroPayload!

    """음성 소개 삭제"""
    deleteVoiceIntro: UpdateProfilePayload!

    # --- 위치 및 공개 범위 ---

    """위치 정보 업데이트"""
    updateProfileLocation(input: UpdateProfileLocationInput!): UpdateProfilePayload!

    """위치 정보 삭제"""
    deleteProfileLocation: UpdateProfilePayload!

    """공개 범위 설정 변경"""
    updatePrivacySettings(input: UpdatePrivacySettingsInput!): UpdateProfilePayload!
}
```

